import react, { useEffect } from 'react';
import { createDrawerNavigator, DrawerContentScrollView } from '@react-navigation/drawer';
import Main from '../componentes/Main';
import LPrecios from '../componentes/LPrecios';
import LClientes from '../componentes/LClientes';
import DetalleProducto from '../componentes/DetalleProducto';
import DetalleCliente from '../componentes/DetalleCliente';
import LogIn from '../componentes/LogIn';
import LPedidos from '../componentes/LPedidos';
import NuevaVenta from '../componentes/NuevaVenta';
import DetallesDelPedido from '../components/DetallesDelPedido';
import Ruler from '../components/Ruler';


import { Text, StyleSheet, Icon } from 'react-native';
import MenuButtonItem from '../components/MenuButtonItem';
/*import { TouchableOpacity } from 'react-native-gesture-handler';*/

const Drawer = createDrawerNavigator()
   
export function DrawerNavigation(){
    
    return (
        <Drawer.Navigator 
            backBehavior="history"
            drawerContent={(props) => <MenuItems{...props} />}>
            <Drawer.Screen
                name="LogIn" 
                component={ LogIn }
                options={{
                    title: 'Pantalla de inicio',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
                    headerShown: false,
            }}/>
            <Drawer.Screen
                name="Main" 
                component={ Main }
                options={{
                    title: 'Pantalla de inicio',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen 
                name="LPrecios" 
                component={ LPrecios } 
                options={{
                    title: 'Lista de precios',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen
                name="DetalleProducto" 
                component={ DetalleProducto }
                icon = "home"
                options={{
                    title: 'Detalle del producto',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
                    //navigationOptions: {icon: 'home' },
            }}/>
            <Drawer.Screen 
                name="LClientes" 
                component={ LClientes } 
                options={{
                    title: 'Lista de Clientes',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen
                name="DetalleCliente" 
                component={ DetalleCliente }
                //icon = "home"
                options={{
                    title: 'Detalle del cliente',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
                    //navigationOptions: {icon: 'home' },
            }}/>
            <Drawer.Screen
                name="NuevaVenta" 
                component={ NuevaVenta }
                //icon = "home"
                options={{
                    title: 'Nueva venta',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen
                name="LPedidos" 
                component={ LPedidos }
                //icon = "home"
                options={{
                    title: 'Lista de pedidos',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen
                name="DetallesDelPedido" 
                component={ DetallesDelPedido }
                //icon = "home"
                options={{
                    title: 'Detalles del Pedido',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
            <Drawer.Screen
                name="Ruler" 
                component={ Ruler }
                //icon = "home"
                options={{
                    title: 'Regla',
                    headerStyle: {backgroundColor: '#193773'},
                    headerTitleStyle: {color: '#FFFF'},
            }}/>
        </Drawer.Navigator>
    )
}

const MenuItems = ({ navigation }) =>{
    const vacio = []
    return (
        <DrawerContentScrollView 
            style={styles.container}
        >
            <Text style={styles.title}>Menú</Text>
            <MenuButtonItem 
                text = "Pantalla de inicio"
                onPress={() => navigation.navigate('Main')}
                icon = "home"
            />
            <MenuButtonItem 
                text = "Lista de precios"
                onPress={() => navigation.navigate('LPrecios')}
                icon = "list"
            />
            <MenuButtonItem 
                text = "Lista de clientes"
                onPress={() => navigation.navigate('LClientes')}
                icon = "list"
            />
            <MenuButtonItem 
                text = "Lista de pedidos"
                onPress={() => navigation.navigate('LPedidos', vacio)}
                icon = "list"
            />
        </DrawerContentScrollView>
    )
}

const styles = StyleSheet.create({
    container: {
        padding: 10,
        backgroundColor: '#193773'
    },
    title: {
        fontSize: 20,
        fontWeight: 'bold',
        marginBottom: 10,
        color: '#FFFFFF',
    },
    item: {
        
    }
})
